import { Component, h, Prop, Element } from '@stencil/core';
import { WdprProgressSegmentStatus, WdprProgressBarSegmentedStep } from '../../models/progress-bar.model';

@Component({
  tag: 'wdpr-progress-bar-segmented',
  shadow: true,
})
export class WdprProgressBarSegmented {
  @Element() el: HTMLWdprProgressBarSegmentedElement;

  @Prop() steps: WdprProgressBarSegmentedStep[] = [];
  @Prop({ reflect: true }) label: boolean = false;
  @Prop() labelText?: string;

  private _getPosition(index: number, total: number): 'start' | 'middle' | 'end' {
    if (total <= 1) return 'middle';
    if (index === 0) return 'start';
    if (index === total - 1) return 'end';

    return 'middle';
  }

  private _getDerivedStatus(step: WdprProgressBarSegmentedStep): WdprProgressSegmentStatus {
    return step.status ?? 'pending';
  }

  private get _barLabel(): string {
    if (this.labelText?.trim()) return this.labelText.trim();

    const total = this.steps.length;

    const activeIndex = this.steps.findIndex(s => this._getDerivedStatus(s) === 'active');
    if (activeIndex >= 0) return `Step ${activeIndex + 1} of ${total}`;

    const hasPending = this.steps.some(s => this._getDerivedStatus(s) === 'pending');
    if (hasPending) return 'Pending';

    return 'Complete';
  }

  render() {
    const totalSteps = this.steps.length;
    const ariaLabel = this.label ? this._barLabel : 'Multi-step progress';

    return (
      <div class="w-full" part="root">
        <div class="flex items-center w-full" role="list" aria-label={ariaLabel} part="segments">
          {this.steps.map((step, index) => {
            const status = this._getDerivedStatus(step);
            const isCurrent = status === 'active';

            return (
              <div class="flex-1" part="segment-wrap" role="listitem" aria-current={isCurrent ? 'step' : null}>
                <wdpr-progress-segment status={status} position={this._getPosition(index, totalSteps)} exportparts="segment:segment"></wdpr-progress-segment>
              </div>
            );
          })}
        </div>

        {this.label ? (
          <div class="mt-050" part="label" aria-hidden="true">
            <div class="label-small text-text-body">{this._barLabel}</div>
          </div>
        ) : null}
      </div>
    );
  }
}
